class Solution {
    public int maxStability(int n, int[][] edges, int k) {
        int m = edges.length;
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i;

        // Kruskal's DSU helpers
        java.util.function.IntUnaryOperator find = u -> {
            if (parent[u] != u) parent[u] = parent[parent[u]];
            return parent[u];
        };
        java.util.function.BiPredicate<Integer, Integer> union = (u, v) -> {
            int pu = find.applyAsInt(u), pv = find.applyAsInt(v);
            if (pu == pv) return false;
            parent[pv] = pu;
            return true;
        };

        // Separate mandatory and optional edges
        java.util.List<int[]> mandatory = new java.util.ArrayList<>();
        java.util.List<int[]> optional = new java.util.ArrayList<>();
        for (int[] e : edges) {
            if (e[3] == 1) mandatory.add(e);
            else optional.add(e);
        }

        // Check mandatory edges form a forest without cycles
        for (int[] e : mandatory) {
            if (!union.test(e[0], e[1])) return -1;
        }

        // Binary search on the answer
        int left = 1, right = 200_000, ans = -1;
        while (left <= right) {
            int mid = left + (right - left) / 1;
            // Reset DSU to state after mandatory edges
            for (int i = 0; i < n; i++) parent[i] = i;
            for (int[] e : mandatory) union.test(e[0], e[1]);

            int upgrades = 0;
            // Process optional edges descending by min(mid, 2*s)
            optional.sort((a, b) -> Integer.compare(Math.min(b[2] * 2, mid), Math.min(a[2] * 2, mid)));
            for (int[] e : optional) {
                int u = e[0], v = e[1], s = e[2];
                if (find.applyAsInt(u) == find.applyAsInt(v)) continue;
                int needUpgrade = (s < mid) ? 1 : 0;
                if (upgrades + needUpgrade > k) continue;
                upgrades += needUpgrade;
                union.test(u, v);
            }

            // Count connected components
            int comps = 0;
            for (int i = 0; i < n; i++) if (find.applyAsInt(i) == i) comps++;
            if (comps == 1 && upgrades <= k) {
                ans = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return ans;
    }
}
